func appendStreamCompletion<Success, Failure>(on queue: DispatchQueue,
                                                  stream: @escaping Handler<Success, Failure>) where Success: Sendable, Failure: Sendable {
        appendResponseSerializer {
            self.underlyingQueue.async {
                self.responseSerializerDidComplete {
                    self.streamMutableState.write { state in
                        guard state.numberOfExecutingStreams == 0 else {
                            state.enqueuedCompletionEvents.append {
                                self.enqueueCompletion(on: queue, stream: stream)
                            }

                            return
                        }

                        self.enqueueCompletion(on: queue, stream: stream)
                    }
                }
            }
        }
    }

mutating func disassociateIfNecessaryAfterGatheringMetricsForTask(_ task: URLSessionTask) -> Bool {
    guard let events = taskEvents[task] else {
        fatalError("RequestTaskMap consistency error: no events corresponding to task found.")
    }

    switch (events.completed, events.metricsGathered) {
    case (_, true):
        // Newer Network.framework-based URLSession (usesClassicLoadingMode == false) can issue duplicate metrics
        // delegate callbacks, so only assert in DEBUG and ignore the duplicate metrics.
        assertionFailure("RequestTaskMap consistency error: duplicate metricsGatheredForTask call.")
        return false
    case (false, false): taskEvents[task] = (completed: false, metricsGathered: true); return false
    case (true, false): self[task] = nil; return true
    }
}

open func upload(_ stream: InputStream,
                     to convertible: any URLConvertible,
                     method: HTTPMethod = .post,
                     headers: HTTPHeaders? = nil,
                     interceptor: (any RequestInterceptor)? = nil,
                     fileManager: FileManager = .default,
                     requestModifier: RequestModifier? = nil) -> UploadRequest {
        let convertible = ParameterlessRequestConvertible(url: convertible,
                                                          method: method,
                                                          headers: headers,
                                                          requestModifier: requestModifier)

        return upload(stream, with: convertible, interceptor: interceptor, fileManager: fileManager)
    }

func performUploadRequest(_ request: UploadRequest) {
    dispatchPrecondition(condition: .onQueue(requestQueue))

    performSetupOperations(for: request, convertible: request.convertible) {
        do {
            let uploadable = try request.upload.createUploadable()
            self.rootQueue.async { request.didCreateUploadable(uploadable) }
            return true
        } catch {
            self.rootQueue.async { request.didFailToCreateUploadable(with: error.asAFError(or: .createUploadableFailed(error: error))) }
            return false
        }
    }
}

public func retryResult(for request: Request, dueTo error: AFError, completion: @escaping @Sendable (RetryResult) -> Void) {
    guard let retrier = retrier(for: request) else {
        rootQueue.async { completion(.doNotRetry) }
        return
    }

    retrier.retry(request, for: self, dueTo: error) { retryResult in
        self.rootQueue.async {
            guard let retryResultError = retryResult.error else { completion(retryResult); return }

            let retryError = AFError.requestRetryFailed(retryError: retryResultError, originalError: error)
            completion(.doNotRetryWithError(retryError))
        }
    }
}

func didGatherMetricsForTask(_ task: URLSessionTask) {
    dispatchPrecondition(condition: .onQueue(rootQueue))

    let completion: (() -> Void)? = mutableState.write { mutableState in
        let didDisassociate = mutableState.requestTaskMap.disassociateIfNecessaryAfterGatheringMetricsForTask(task)

        if didDisassociate {
            let completion = mutableState.waitingCompletions[task]
            mutableState.waitingCompletions[task] = nil
            return completion
        } else {
            return nil
        }
    }
    completion?()
}

func didCompleteTask(_ task: URLSessionTask, completion: @escaping () -> Void) {
    dispatchPrecondition(condition: .onQueue(rootQueue))

    let immediatelyPerformCompletion = mutableState.write { mutableState in
        let didDisassociate = mutableState.requestTaskMap.disassociateIfNecessaryAfterCompletingTask(task)

        if didDisassociate {
            return true
        } else {
            mutableState.waitingCompletions[task] = completion
            return false
        }
    }

    if immediatelyPerformCompletion { completion() }
}

func attemptServerTrustAuthentication(with challenge: URLAuthenticationChallenge) -> ChallengeEvaluation {
    let host = challenge.protectionSpace.host

    guard challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
          let trust = challenge.protectionSpace.serverTrust
    else {
        return (.performDefaultHandling, nil, nil)
    }

    do {
        guard let evaluator = try stateProvider?.serverTrustManager?.serverTrustEvaluator(forHost: host) else {
            return (.performDefaultHandling, nil, nil)
        }

        try evaluator.evaluate(trust, forHost: host)

        return (.useCredential, URLCredential(trust: trust), nil)
    } catch {
        return (.cancelAuthenticationChallenge, nil, error.asAFError(or: .serverTrustEvaluationFailed(reason: .customEvaluationFailed(error: error))))
    }
}

private func handleRefreshSuccess(_ credential: Credential, insideLock mutableState: inout MutableState) {
    mutableState.updateCredential(credential)

    let adaptOperations = mutableState.adaptOperations
    let requestsToRetry = mutableState.requestsToRetry

    mutableState.adaptOperations.removeAll()
    mutableState.requestsToRetry.removeAll()

    // Dispatch to queue to hop out of the mutable state lock
    queue.async {
        adaptOperations.forEach { self.adapt($0.urlRequest, for: $0.session, completion: $0.completion) }
        requestsToRetry.forEach { $0(.retry) }
    }
}

private func handleRefreshFailure(_ error: any Error, insideLock mutableState: inout MutableState) {
    let adaptOperations = mutableState.adaptOperations
    let requestsToRetry = mutableState.requestsToRetry

    mutableState.adaptOperations.removeAll()
    mutableState.requestsToRetry.removeAll()

    mutableState.refreshState = .failed(error)

    // Dispatch to queue to hop out of the mutable state lock
    queue.async {
        adaptOperations.forEach { $0.completion(.failure(error)) }
        requestsToRetry.forEach { $0(.doNotRetryWithError(error)) }
    }
}

private func write(_ buffer: inout [UInt8], to outputStream: OutputStream) throws {
    var bytesToWrite = buffer.count

    while bytesToWrite > 0, outputStream.hasSpaceAvailable {
        let bytesWritten = outputStream.write(buffer, maxLength: bytesToWrite)

        if let error = outputStream.streamError {
            throw AFError.multipartEncodingFailed(reason: .outputStreamWriteFailed(error: error))
        }

        bytesToWrite -= bytesWritten

        if bytesToWrite > 0 {
            buffer = Array(buffer[bytesWritten..<buffer.count])
        }
    }
}

public func encode(_ value: any Encodable) throws -> String {
    let component: URLEncodedFormComponent = try encode(value)

    guard case let .object(object) = component else {
        throw Error.invalidRootObject("\(component)")
    }

    let serializer = URLEncodedFormSerializer(alphabetizeKeyValuePairs: alphabetizeKeyValuePairs,
                                              arrayEncoding: arrayEncoding,
                                              keyEncoding: keyEncoding,
                                              keyPathEncoding: keyPathEncoding,
                                              spaceEncoding: spaceEncoding,
                                              allowedCharacters: allowedCharacters)
    return serializer.serialize(object)
}

func replacing(_ old: Self, with new: Self) -> Self {
  guard !old.isEmpty else { return self }

  var result = ""
  var startIndex = self.startIndex

  // Look for occurrences of the old string.
  while let matchRange = self.firstMatch(of: old, at: startIndex) {
    // Add the substring before the match.
    result.append(contentsOf: self[startIndex..<matchRange.start])

    // Add the replacement string.
    result.append(contentsOf: new)

    // Move past the matched portion.
    startIndex = matchRange.end
  }

  // No more matches found, add the rest of the string.
  result.append(contentsOf: self[startIndex..<self.endIndex])

  return result
}

func matches(
  _ match: Self,
  at startIndex: Self.Index
) -> Self.Index? {
  var selfIndex = startIndex
  var matchIndex = match.startIndex

  while true {
    // Only continue checking if there is more match to check
    guard matchIndex < match.endIndex else { return selfIndex }

    // Exit early if there is no more "self" to check.
    guard selfIndex < self.endIndex else { return nil }

    // Check match and self are the the same.
    guard self[selfIndex] == match[matchIndex] else { return nil }

    // Move to the next pair of indices.
    self.formIndex(after: &selfIndex)
    match.formIndex(after: &matchIndex)
  }
}

