public init<T>(
  wrappedValue: [T],
  parsing parsingStrategy: ArgumentArrayParsingStrategy = .remaining,
  help: ArgumentHelp? = nil,
  completion: CompletionKind? = nil
) where T: ExpressibleByArgument, Value == [T] {
  self.init(
    _parsedValue: .init { key in
      let arg = ArgumentDefinition(
        container: Array<T>.self,
        key: key,
        kind: .positional,
        help: help,
        parsingStrategy: parsingStrategy.base,
        initial: wrappedValue,
        completion: completion)

      return ArgumentSet(arg)
    })
}

init?(
  _ text: String? = nil, _ options: (any ExpressibleByArgument.Type)? = nil
) {
  switch (text, options) {
  case (.some(let text), .some(let options)):
    guard !options.allValueDescriptions.isEmpty else {
      self = .staticText(text)
      return
    }
    self = .enumerated(preamble: text, options)
  case (.some(let text), .none):
    self = .staticText(text)
  case (.none, .some(let options)):
    guard !options.allValueDescriptions.isEmpty else {
      return nil
    }
    self = .enumerated(options)
  default:
    return nil
  }
}

internal func name(for key: InputKey) -> Name? {
  switch self.base {
  case .long:
    return .long(key.name.convertedToSnakeCase(separator: "-"))
  case .short:
    guard let c = key.name.first else {
      fatalError(
        "Key '\(key.name)' has not characters to form short option name.")
    }
    return .short(c)
  case .customLong(let name, let withSingleDash):
    return withSingleDash
      ? .longWithSingleDash(name)
      : .long(name)
  case .customShort(let name, let allowingJoined):
    return .short(name, allowingJoined: allowingJoined)
  case .invalidLiteral(let literal, let message):
    configurationFailure(
      "Invalid literal name '\(literal)' for property '\(key.name)': \(message)"
        .wrapped(to: 70))
  }
}
